import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowRight, Calendar, Clock, Heart, MessageSquare, ArrowLeft, Send } from "lucide-react";

const blogData = [
  {
    id: 1,
    title: "Designing Better UX in Enterprise Apps",
    excerpt: "Principles to create usable, accessible enterprise UIs.",
    date: "8/10/2024",
    readTime: "7 min",
    tag: "UX",
    likes: 0,
    comments: 0,
    link: "#",
    image: "/blog-ux.png",
    content: [
      { type: "paragraph", text: "Most people think about great user experience when using consumer apps like shopping or social media platforms. But enterprise applications—tools used by employees inside companies—often struggle with poor usability." },
      { type: "paragraph", text: "Employees rely on enterprise apps every day for tasks like managing customers, handling data, or tracking projects. When these systems are confusing or slow, productivity drops and frustration increases. That's why good UX in enterprise applications is essential." },
      { type: "subtitle", text: "1. Understand the Users" },
      { type: "paragraph", text: "Enterprise apps are used by different teams such as sales, HR, finance, and operations. Each group has different needs and workflows. Designers should study how employees actually work and design tools that support those real tasks." },
      { type: "subtitle", text: "2. Reduce Complexity" },
      { type: "paragraph", text: "Enterprise systems usually contain many features. Instead of overwhelming users with everything at once, good UX focuses on simplicity and clarity. Important information should be easy to find, and advanced options should appear only when needed." },
      { type: "subtitle", text: "3. Design Around Workflows" },
      { type: "paragraph", text: "Employees often follow a clear process when completing tasks. A well-designed application supports this natural workflow instead of forcing users to jump between multiple pages or tools." },
      { type: "subtitle", text: "4. Focus on Speed and Efficiency" },
      { type: "paragraph", text: "Many enterprise tasks are repetitive. Small improvements like faster loading pages, keyboard shortcuts, or auto-filled fields can save a lot of time for employees who use the system daily." },
      { type: "subtitle", text: "Conclusion" },
      { type: "paragraph", text: "Good enterprise UX is not just about design—it's about making work easier. When applications are simple, efficient, and aligned with real workflows, employees can focus on their work instead of struggling with the software." }
    ]
  }
];

const BlogCard = ({ post, onRead }) => (
  <motion.div
    initial={{ opacity: 0, y: 20 }}
    whileInView={{ opacity: 1, y: 0 }}
    transition={{ duration: 0.5 }}
    viewport={{ once: true }}
    className="flex flex-col bg-card rounded-[14px] overflow-hidden border border-textPrimary/5 group hover:border-primary/30 hover:shadow-[0_0_15px_rgba(0,208,156,0.1)] transition-all duration-300"
  >
    <div className="relative aspect-[16/10] w-full overflow-hidden bg-dark">
      <div className="absolute inset-0 flex items-center justify-center text-textSecondary text-sm">
        Image Placeholder
      </div>
      <img src={post.image} alt={post.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500 absolute inset-0 z-10" onError={(e) => { e.target.style.display = 'none'; }} />
      <div className="absolute top-3 left-3 bg-primary text-black text-[10px] font-bold tracking-wide px-2 py-0.5 rounded-full z-20 shadow-lg uppercase">
        {post.tag}
      </div>
    </div>

    <div className="p-5 flex flex-col flex-grow">
      <h3 className="text-lg font-bold text-textPrimary mb-2.5 leading-snug font-serif tracking-wide">{post.title}</h3>
      <p className="text-textSecondary text-sm mb-6 flex-grow leading-relaxed">
        {post.excerpt}
      </p>

      <div className="flex items-center justify-between text-[11px] font-medium text-textSecondary/70 mb-4 px-0.5">
        <div className="flex items-center gap-1.5">
          <Calendar size={13} />
          <span>{post.date}</span>
        </div>
        <div className="flex items-center gap-1.5">
          <Clock size={13} />
          <span>{post.readTime}</span>
        </div>
      </div>

      <div className="pt-4 border-t border-textPrimary/10 flex items-center justify-between px-0.5 mt-auto">
        <div className="flex items-center gap-3.5 text-textSecondary/70 text-[11px] font-medium">
          <div className="flex items-center gap-1.5 hover:text-textPrimary cursor-pointer transition-colors group/heart">
            <Heart size={14} className="group-hover/heart:fill-red-500 group-hover/heart:text-red-500 transition-colors" /> {post.likes}
          </div>
          <div className="flex items-center gap-1.5 hover:text-textPrimary cursor-pointer transition-colors">
            <MessageSquare size={14} /> {post.comments}
          </div>
        </div>

        <button onClick={() => onRead(post)} className="inline-flex items-center gap-1 text-primary hover:brightness-125 font-medium text-[12px] transition-all">
          Read More <ArrowRight size={14} className="mt-px" />
        </button>
      </div>
    </div>
  </motion.div>
);

const Blogs = ({ viewState = 'home', onViewChange, activePost: externalActive, setActivePost: externalSetActive }) => {
  const [blogs, setBlogs] = useState(blogData);
  const [commentForm, setCommentForm] = useState({ name: '', email: '', text: '' });
  const [localActive, setLocalActive] = useState(null);

  const activePost = externalActive !== undefined ? externalActive : localActive;
  const setActivePost = externalSetActive || setLocalActive;

  const handleReadPost = (post) => {
    setActivePost(post);
    if (onViewChange) onViewChange('reading_blog');
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleClosePost = () => {
    setActivePost(null);
    if (onViewChange) onViewChange('home');
    setTimeout(() => {
      const bSection = document.getElementById("blogs");
      if (bSection) window.scrollTo({ top: bSection.offsetTop - 100, behavior: "smooth" });
    }, 50);
  };

  const handleLike = () => {
    if (!activePost) return;
    const isLiked = activePost.isLiked;
    const updatedPost = { 
      ...activePost, 
      likes: isLiked ? activePost.likes - 1 : activePost.likes + 1, 
      isLiked: !isLiked 
    };

    setActivePost(updatedPost);
    setBlogs(prev => prev.map(b => b.id === activePost.id ? updatedPost : b));
  };

  const handleCommentSubmit = (e) => {
    e.preventDefault();
    if (!commentForm.name.trim() || !commentForm.text.trim()) return;

    const newComment = {
      id: Date.now(),
      name: commentForm.name,
      text: commentForm.text,
      date: new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })
    };

    const currentComments = activePost.commentsList || [];
    const updatedPost = { 
      ...activePost, 
      comments: activePost.comments + 1,
      commentsList: [...currentComments, newComment]
    };

    setActivePost(updatedPost);
    setBlogs(prev => prev.map(b => b.id === activePost.id ? updatedPost : b));
    setCommentForm({ name: '', email: '', text: '' });
  };

  return (
    <section id="blogs" className="py-8 px-6 md:px-12 bg-dark min-h-screen">
      <div className="max-w-4xl flex-col flex mx-auto">
        <AnimatePresence mode="wait">
          {!activePost ? (
            <motion.div 
              key="grid"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.3 }}
            >
              {viewState === 'all_blogs' && (
                <div className="mb-10 max-w-5xl mx-auto">
                  <button 
                    onClick={() => {
                      if (onViewChange) onViewChange('home');
                      setTimeout(() => {
                        const bSection = document.getElementById("blogs");
                        if (bSection) window.scrollTo({ top: bSection.offsetTop - 100, behavior: "smooth" });
                      }, 50);
                    }}
                    className="flex items-center gap-2 text-primary hover:text-[#050505] transition-colors font-bold uppercase tracking-wide text-xs bg-primary/10 border border-primary/20 hover:bg-primary px-4 py-2 rounded-lg w-max shadow-md"
                  >
                    <ArrowLeft size={16} strokeWidth={2.5} /> Back to Home
                  </button>
                </div>
              )}

              <div className="mb-14 text-center">
                <h2 className="text-4xl md:text-[40px] font-black text-textPrimary mb-4 font-serif tracking-tight">Latest Blogs</h2>
                <p className="text-textSecondary mb-6 max-w-2xl mx-auto text-[15px] font-medium leading-relaxed">
                  Sharing my thoughts, experiences, and insights from the world of technology and development
                </p>
                <div className="w-20 h-1 bg-primary mx-auto rounded-full"></div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-8 max-w-5xl mx-auto">
                {blogs.map((post) => (
                  <BlogCard key={post.id} post={post} onRead={handleReadPost} />
                ))}
              </div>

              {viewState !== 'all_blogs' && (
                <div className="mt-16 flex justify-center">
                  <button 
                    onClick={() => {
                      if (onViewChange) onViewChange('all_blogs');
                      window.scrollTo({ top: 0, behavior: "smooth" });
                    }}
                    className="inline-flex items-center justify-center px-6 py-2.5 rounded-lg border border-textPrimary/20 text-textSecondary hover:text-textPrimary hover:bg-textPrimary/5 font-medium text-sm transition-all duration-300 bg-transparent"
                  >
                    Show All Blogs
                  </button>
                </div>
              )}
            </motion.div>
          ) : (
            <motion.div 
              key="reader"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              transition={{ duration: 0.4 }}
              className="w-full"
            >
              <button 
                onClick={handleClosePost}
                className="flex items-center gap-2 text-primary hover:text-[#050505] transition-colors font-bold uppercase tracking-wide text-xs bg-primary/10 border border-primary/20 hover:bg-primary px-4 py-2 rounded-lg w-max mb-10 shadow-md"
              >
                <ArrowLeft size={16} strokeWidth={2.5} /> Back to Blogs
              </button>

              <h1 className="text-4xl md:text-[44px] font-bold text-textPrimary mb-4 font-serif leading-tight">
                {activePost.title}
              </h1>

              <div className="flex items-center gap-3 text-textSecondary text-[13px] font-medium mb-8">
                <span>{activePost.tag}</span>
                <span className="w-1 h-1 rounded-full bg-textSecondary/50"></span>
                <span>{activePost.readTime}</span>
                <span className="w-1 h-1 rounded-full bg-textSecondary/50"></span>
                <span>{activePost.date}</span>
              </div>

              <div className="w-full h-auto aspect-[21/9] rounded-2xl overflow-hidden mb-10 border border-textPrimary/10 shadow-xl bg-card">
                <img src={activePost.image} alt={activePost.title} className="w-full h-full object-cover" onError={(e) => { e.target.style.display = 'none'; }} />
              </div>

              <article className="prose prose-invert max-w-none mb-12 border-b border-textPrimary/10 pb-10">
                <h2 className="text-xl font-bold text-textPrimary mb-4">{activePost.title}</h2>
                {activePost.content.map((block, idx) => {
                  if (block.type === 'subtitle') {
                    return <h3 key={idx} className="text-lg font-bold text-textPrimary mt-8 mb-3">{block.text}</h3>
                  }
                  return <p key={idx} className="text-textSecondary/90 text-[15px] leading-relaxed mb-4">{block.text}</p>
                })}
              </article>

              <div className="flex items-center gap-4 mb-14 border-b border-textPrimary/10 pb-10">
                <button onClick={handleLike} className={`flex items-center gap-2 px-4 py-2 rounded-full border border-textPrimary/10 hover:bg-textPrimary/5 transition-all text-sm font-medium ${activePost.isLiked ? 'bg-primary/10 text-primary' : 'bg-card text-textSecondary hover:text-textPrimary'}`}>
                  <Heart size={16} className={activePost.isLiked ? 'fill-primary' : ''} /> {activePost.likes} Likes
                </button>
                <div className="flex items-center gap-2 px-4 py-2 rounded-full border border-textPrimary/10 bg-card text-textSecondary transition-all text-sm font-medium">
                  <MessageSquare size={16} /> {activePost.comments} Comments
                </div>
              </div>

              <div className="max-w-2xl mb-12">
                <h3 className="text-xl font-bold text-textPrimary mb-6">{activePost.comments} Comments</h3>

                <div className="space-y-6 mb-10">
                  {(!activePost.commentsList || activePost.commentsList.length === 0) ? (
                    <div className="text-textSecondary text-[13px] font-medium py-4 px-6 bg-dark/30 rounded-xl border border-textPrimary/5">
                      No comments yet. Be the first to start the conversation!
                    </div>
                  ) : (
                    activePost.commentsList.map(comment => (
                      <div key={comment.id} className="flex gap-4">
                        <div className="w-10 h-10 rounded-full bg-textPrimary/10 border border-textPrimary/10 flex items-center justify-center text-textPrimary font-bold shrink-0">
                          {comment.name.charAt(0).toUpperCase()}
                        </div>
                        <div className="flex flex-col">
                          <div className="flex items-center gap-2 mb-1">
                            <span className="font-bold text-textPrimary text-[14px]">{comment.name}</span>
                            <span className="text-textSecondary text-[11px]">{comment.date}</span>
                          </div>
                          <p className="text-textSecondary text-[13px] leading-relaxed">
                            {comment.text}
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>

                <div className="bg-card border border-textPrimary/10 rounded-2xl p-6 md:p-8 shadow-xl">
                  <h3 className="text-xl font-bold text-textPrimary mb-6">Leave a Comment</h3>
                  <form className="space-y-4" onSubmit={handleCommentSubmit}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="flex flex-col gap-1.5">
                        <label className="text-[13px] font-bold text-textPrimary">Name *</label>
                        <input type="text" value={commentForm.name} onChange={(e) => setCommentForm({...commentForm, name: e.target.value})} placeholder="Your name" className="bg-dark/50 border border-textPrimary/10 rounded-lg px-4 py-3 placeholder-textSecondary/50 text-textPrimary focus:outline-none focus:border-primary transition-colors text-sm" required />
                      </div>
                      <div className="flex flex-col gap-1.5">
                        <label className="text-[13px] font-bold text-textPrimary">Email *</label>
                        <input type="email" value={commentForm.email} onChange={(e) => setCommentForm({...commentForm, email: e.target.value})} placeholder="your.email@example.com" className="bg-dark/50 border border-textPrimary/10 rounded-lg px-4 py-3 placeholder-textSecondary/50 text-textPrimary focus:outline-none focus:border-primary transition-colors text-sm" required />
                      </div>
                    </div>
                    <div className="flex flex-col gap-1.5 pt-2">
                      <label className="text-[13px] font-bold text-textPrimary">Comment *</label>
                      <textarea rows="4" value={commentForm.text} onChange={(e) => setCommentForm({...commentForm, text: e.target.value})} placeholder="Share your thoughts..." className="bg-dark/50 border border-textPrimary/10 rounded-lg px-4 py-3 placeholder-textSecondary/50 text-textPrimary focus:outline-none focus:border-primary transition-colors text-sm custom-scrollbar resize-none" required></textarea>
                    </div>
                    <div className="pt-2">
                      <button type="submit" className="flex items-center gap-2 bg-primary hover:bg-secondary text-[#050505] px-6 py-2.5 rounded-lg font-bold transition-colors text-sm shadow-[0_0_15px_rgba(0,208,156,0.3)]">
                        <Send size={16} className="text-[#050505]" /> Submit Comment
                      </button>
                    </div>
                  </form>
                </div>
              </div>

            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </section>
  );
};

export default Blogs;

